        self.quant_method.process_weights_after_loading(layer)

def apply(
    self,
    layer: torch.nn.Module,
    x: torch.Tensor,
    bias: torch.Tensor | None = None,
) -> torch.Tensor:
    if isinstance(layer, RowParallelLinear):
